const hamburgerBtn=document.getElementById('hamburgerBtn');const navMenu=document.getElementById('navMenu');const navLinks=document.querySelectorAll('.nav-links a');const themeToggle=document.getElementById('themeToggle');const themeIcon=document.getElementById('themeIcon');const filterBtns=document.querySelectorAll('.filter-btn');const projectCards=document.querySelectorAll('.project-card');const contactForm=document.getElementById('contactForm');const formConfirmation=document.getElementById('formConfirmation');const prefersReducedMotion=window.matchMedia('(prefers-reduced-motion:reduce)').matches;const closeNavMenu=()=>{if(!hamburgerBtn || !navMenu)return;hamburgerBtn.classList.remove('active');navMenu.classList.remove('active');hamburgerBtn.setAttribute('aria-expanded','false');};if(hamburgerBtn && navMenu){hamburgerBtn.addEventListener('click',()=>{hamburgerBtn.classList.toggle('active');navMenu.classList.toggle('active');hamburgerBtn.setAttribute('aria-expanded',navMenu.classList.contains('active'));});navLinks.forEach((link)=>{link.addEventListener('click',closeNavMenu);});document.addEventListener('click',(e)=>{if(!e.target.closest('nav')){closeNavMenu();}});}const currentTheme=localStorage.getItem('theme')|| 'dark-mode';if(currentTheme==='light-mode'){document.body.classList.add('light-mode');if(themeIcon)themeIcon.textContent='◐';}else{document.body.classList.remove('light-mode');if(themeIcon)themeIcon.textContent='☀';}if(themeToggle){themeToggle.addEventListener('click',()=>{document.body.classList.toggle('light-mode');const isLightMode=document.body.classList.contains('light-mode');localStorage.setItem('theme',isLightMode ? 'light-mode':'dark-mode');if(themeIcon)themeIcon.textContent=isLightMode ? '◐':'☀';});}const currentPage=window.location.pathname.split('/').pop()|| 'index.html';document.querySelectorAll('.nav-link').forEach((link)=>{const href=link.getAttribute('href');link.classList.toggle('active',href===currentPage);});if(filterBtns.length>0 && projectCards.length>0){filterBtns.forEach((btn)=>{btn.addEventListener('click',()=>{const filter=btn.getAttribute('data-filter');filterBtns.forEach((b)=>b.classList.remove('active'));btn.classList.add('active');projectCards.forEach((card)=>{const isVisible=filter==='all' || card.getAttribute('data-category')===filter;card.style.display=isVisible ? 'flex':'none';if(isVisible){card.style.animation='fadeIn 0.6s ease';}});});});}const showFormConfirmation=()=>{if(!contactForm || !formConfirmation)return;contactForm.style.display='none';formConfirmation.classList.add('show');setTimeout(()=>{contactForm.reset();contactForm.style.display='block';formConfirmation.classList.remove('show');},5000);};if(contactForm && formConfirmation){contactForm.addEventListener('submit',(e)=>{e.preventDefault();showFormConfirmation();});}if(!prefersReducedMotion){document.body.classList.add('motion-ready');document.querySelectorAll('.nav-links .nav-link').forEach((link,index)=>{link.style.setProperty('--nav-delay',`${140+index * 80}ms`);});requestAnimationFrame(()=>{document.body.classList.add('motion-entered');});}const applyRevealTargets=()=>{const revealGroups=[{selector:'.section-header',variant:'reveal-left',step:0},{selector:'.timeline-item',variant:'reveal-left',step:90},{selector:'.highlight-card',variant:'reveal-scale',step:120},{selector:'.project-card',variant:'reveal-up',step:90},{selector:'.social-card',variant:'reveal-scale',step:90}];revealGroups.forEach(({selector,variant,step})=>{document.querySelectorAll(selector).forEach((element,index)=>{element.classList.add('reveal',variant);element.style.setProperty('--reveal-delay',`${index * step}ms`);});});};if('IntersectionObserver' in window && !prefersReducedMotion){applyRevealTargets();const observer=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){entry.target.classList.add('animate');observer.unobserve(entry.target);}});},{threshold:0.1,rootMargin:'0px 0px -40px 0px'});document.querySelectorAll('.reveal').forEach((element)=>{observer.observe(element);});}document.querySelectorAll('a[href^="#"]').forEach((anchor)=>{anchor.addEventListener('click',function(e){const href=this.getAttribute('href');if(href !=='#'){e.preventDefault();const target=document.querySelector(href);if(target){target.scrollIntoView({behavior:'smooth',block:'start'});}}});});document.addEventListener('keydown',(e)=>{if(e.key==='Tab'){document.body.classList.add('keyboard-nav');}});document.addEventListener('mousedown',()=>{document.body.classList.remove('keyboard-nav');});